mapper.select:
SELECT id, tag_name, tag_type, parent_tag_id, status, remark, created_by, created_time, level FROM goods_tag_category
AND tag_type = #{tagType}
AND tag_name LIKE CONCAT('%', #{tagName}, '%')
AND status = #{status}
AND DATE_FORMAT(created_time, '%Y-%m') = DATE_FORMAT(#{createdTimeMonth}, '%Y-%m')
AND parent_tag_id = #{parentTagId}
AND level = #{level}
ORDER BY created_time DESC
